import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = ({ onSearch, onClear, onCreate }) => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    // --- ОБЪЕКТЫ ДЕЙСТВИЙ (КНОПКИ) ---
    const actions = [
        { name: '🔍 Поиск', action: onSearch, color: '#f0f2f5', textColor: '#333' },
        { name: '🧹 Очистить', action: onClear, color: '#fff', border: '1px solid #eee' },
    ];

    // Добавляем "Создать", если пользователь — админ или продавец
    if (user?.role === 'admin' || user?.role === 'seller') {
        actions.push({ name: '➕ Создать товар', action: onCreate, color: '#E8F5E9', textColor: '#2E7D32' });
    }

    return (
        <nav style={styles.nav}>
            <div style={styles.container}>
                <div style={styles.leftSection}>
                    <Link to="/" style={styles.logo}>🛒 Магазин</Link>
                    <Link to="/products" style={styles.mainLink}>Главная</Link>
                </div>

                <div style={styles.rightSection}>
                    {/* Рендерим функциональные кнопки из массива */}
                    <div style={styles.actionGroup}>
                        {actions.map((btn, index) => (
                            <button 
                                key={index} 
                                onClick={btn.action} 
                                style={{
                                    ...styles.actionBtn, 
                                    backgroundColor: btn.color,
                                    color: btn.textColor || '#333',
                                    border: btn.border || 'none'
                                }}
                            >
                                {btn.name}
                            </button>
                        ))}
                    </div>

                    <div style={styles.divider}></div>

                    {user ? (
                        <div style={styles.userZone}>
                            <span style={styles.username}>@{user.username}</span>
                            <button onClick={() => { logout(); navigate('/login'); }} style={styles.logoutBtn}>Выйти</button>
                        </div>
                    ) : (
                        <Link to="/login" style={styles.loginBtn}>Войти</Link>
                    )}
                </div>
            </div>
        </nav>
    );
};

const styles = {
    nav: { backgroundColor: '#fff', padding: '12px 0', boxShadow: '0 2px 10px rgba(0,0,0,0.03)', position: 'sticky', top: 0, zIndex: 1000 },
    container: { maxWidth: '1200px', margin: '0 auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 20px' },
    leftSection: { display: 'flex', alignItems: 'center', gap: '30px' },
    rightSection: { display: 'flex', alignItems: 'center', gap: '20px' },
    logo: { fontSize: '20px', fontWeight: '800', color: '#1a1a1a', textDecoration: 'none' },
    mainLink: { textDecoration: 'none', color: '#007AFF', fontWeight: '700', fontSize: '15px' },
    actionGroup: { display: 'flex', gap: '8px' },
    actionBtn: {
        padding: '8px 14px',
        borderRadius: '10px',
        fontSize: '13px',
        fontWeight: '600',
        cursor: 'pointer',
        transition: '0.2s',
    },
    divider: { width: '1px', height: '24px', backgroundColor: '#eee' },
    userZone: { display: 'flex', alignItems: 'center', gap: '12px' },
    username: { fontSize: '13px', fontWeight: '700', color: '#555' },
    logoutBtn: { padding: '6px 12px', borderRadius: '8px', border: '1px solid #ff4d4f', backgroundColor: '#fff', color: '#ff4d4f', cursor: 'pointer', fontSize: '12px' },
    loginBtn: { textDecoration: 'none', color: '#007AFF', fontWeight: '700' }
};

export default Navbar;
